const _norm = (s) => String(s||'').toLowerCase().replace(/\s+/g,' ').trim();
const _NORM = {}; for (const k of Object.keys(CNS_LIFT_TIER)) _NORM[_norm(k)] = CNS_LIFT_TIER[k];
// Is this exercise one of the high-CNS barbell lifts? (exact, then normalized)
export function cnsLiftTier(name) { return CNS_LIFT_TIER[name] || _NORM[_norm(name)] || null; }
export const isCnsLift = (name) => cnsLiftTier(name) != null;
